create table public.profiles (id uuid primary key references auth.users on delete cascade, google_id text unique, username text unique not null, avatar text, total_games int not null default 0, total_wins int not null default 0, emperor_games int not null default 0, emperor_wins int not null default 0, rebel_games int not null default 0, rebel_wins int not null default 0, loyalist_games int not null default 0, loyalist_wins int not null default 0, traitor_games int not null default 0, traitor_wins int not null default 0, most_played_role text, best_role text, favorite_character text, created_at timestamptz not null default now());
create table public.game_sessions (id uuid primary key default gen_random_uuid(), status text not null, started_at timestamptz, ended_at timestamptz, turns int not null default 0, winner_roles text[]);
create table public.game_participants (game_id uuid references public.game_sessions on delete cascade, user_id uuid references public.profiles on delete cascade, role text, character_id text, won boolean, primary key(game_id,user_id));
create table public.game_actions (id bigint generated always as identity primary key, game_id uuid references public.game_sessions on delete cascade, actor_id uuid references public.profiles, payload jsonb not null, created_at timestamptz not null default now());
alter table public.profiles enable row level security; create policy "profiles visible" on public.profiles for select using (true); create policy "users update self" on public.profiles for update using (auth.uid()=id);
